        }

        if ((count($resourceRecords) > 10000)) {
            throw new \InvalidArgumentException('invalid value for $resourceRecords when calling Zone., number of items must be less than or equal to 10000.');
        }
        if ((count($resourceRecords) < 0)) {
            throw new \InvalidArgumentException('invalid length for $resourceRecords when calling Zone., number of items must be greater than or equal to 0.');
        }
        $this->container['resourceRecords'] = $resourceRecords;

        return $this;
    }

